#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S1[101], S2[101];
        scanf("%s %s", S1, S2);
        int len = strlen(S1);
        int minDiff = 0, maxDiff = 0;
        for (int i = 0; i < len; ++i) {
            if (S1[i] != S2[i]) {
                if (S1[i] != '?' && S2[i] != '?') {
                    minDiff++;
                }
                maxDiff++;
            } else {
                // characters are equal; only case where max does NOT increase is when both are known and equal
                // when both are '?' they are equal now but we can make them different
                if (S1[i] == '?' && S2[i] == '?') {
                    maxDiff++;
                }
            }
        }
        printf("%d %d\n", minDiff, maxDiff);
    }
    return 0;
}

