import sys

def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        s1 = data[idx].strip(); idx += 1
        s2 = data[idx].strip(); idx += 1
        min_diff = 0
        max_diff = 0
        for ch1, ch2 in zip(s1, s2):
            if ch1 != ch2:
                if ch1 != '?' and ch2 != '?':
                    min_diff += 1
                max_diff += 1
            else:
                if ch1 == '?' and ch2 == '?':
                    max_diff += 1
        out_lines.append(f"{min_diff} {max_diff}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

